import { useState } from 'react'
import { ChevronDownIcon, MagnifyingGlassIcon } from '@heroicons/react/20/solid'

export default function SearchPage() {
  const [dropdownOpen, setDropdownOpen] = useState(false)
  const [selectedCategory, setSelectedCategory] = useState("All categories")
  const [searchResults, setSearchResults] = useState([])
  const [searchQuery, setSearchQuery] = useState('')
  const [itemsPerPage, setItemsPerPage] = useState(5)
  const [currentPage, setCurrentPage] = useState(1)
  const [totalResults, setTotalResults] = useState(0)
  const { isAuthenticated, user } = useAuth();
  const [selectedDestinations, setSelectedDestinations] = useState([]);
  const [userListsCount, setUserListsCount] = useState(0);

  useEffect(() => {
    const fetchUserListsCount = async () => {
      if (isAuthenticated) {
        try {
          const response = await fetch(`${config.api.baseUrl}/api/lists`, {
            headers: {
              'x-auth-token': localStorage.getItem('token')
            }
          });
          const lists = await response.json();
          const userOwnedLists = lists.filter(list => list.userId._id === user._id);
          setUserListsCount(userOwnedLists.length);
        } catch (error) {
          console.error('Error fetching user lists:', error);
        }
      }
    };

    fetchUserListsCount();
  }, [isAuthenticated, user]);

  const toggleDropdown = () => {
    setDropdownOpen(!dropdownOpen)
  }

  const handleCategorySelect = (category) => {
    setSelectedCategory(category)
    setDropdownOpen(false)
  }

  const handleSearch = async (e) => {
    if (e) e.preventDefault()

    const normalizedQuery = searchQuery.trim()

    try {
        const response = await fetch(
            `http://localhost:3000/api/destinations/search?` + 
            `field=${selectedCategory.toLowerCase()}&` +
            `${normalizedQuery ? `pattern=${encodeURIComponent(normalizedQuery)}&` : ''}` +
            `limit=${itemsPerPage}&` +
            `skip=${(currentPage - 1) * itemsPerPage}`
        )
        const data = await response.json()
        setSearchResults(data.results)
        setTotalResults(data.total)
    } catch (error) {
        console.error('Error fetching search results:', error)
    }
  }

  const handlePageChange = (newPage) => {
    setCurrentPage(newPage)
    handleSearch(new Event('submit'))
  }

  const handleAddToList = (destination) => {
    if (!selectedDestinations.find(d => d._id === destination._id)) {
      setSelectedDestinations([...selectedDestinations, destination]);
    }
  };

  const handleRemoveFromList = (destinationId) => {
    setSelectedDestinations(selectedDestinations.filter(d => d._id !== destinationId));
  };

  const handleListCreated = () => {
    setSelectedDestinations([]);
  };

  return (
    <div className="isolate bg-cream-50 dark:bg-gray-900 px-8 py-28 sm:py-36 lg:px-10 min-h-screen">
      <div className="mx-auto max-w-3xl text-center">
        <h2 className="text-balance text-4xl font-serif font-normal tracking-tight text-soft-blue-800 dark:text-gray-100 sm:text-5xl">search for news</h2>
        <p className="mt-6 text-sm text-soft-blue-600 dark:text-gray-400">Type in keywords, topics, or categories to find personalized articles.</p>

        <form onSubmit={handleSearch} className="max-w-xl mx-auto mt-8">
          <div className="flex relative">
            <button 
              id="dropdown-button" 
              onClick={toggleDropdown} 
              className="flex-shrink-0 z-10 inline-flex items-center py-2.5 px-4 text-sm font-medium text-soft-blue-700 dark:text-gray-300 bg-white dark:bg-gray-800 border border-soft-blue-200 dark:border-gray-700 rounded-l-xl hover:bg-soft-blue-50 dark:hover:bg-gray-700 focus:ring-2 focus:ring-inset focus:ring-soft-blue-500 transition-colors"
              type="button">
              {selectedCategory} 
              <ChevronDownIcon className="w-4 h-4 ml-2" />
            </button>

            {dropdownOpen && (
              <div className="absolute z-10 bg-white dark:bg-gray-800 divide-y divide-soft-blue-100 dark:divide-gray-700 rounded-xl shadow-lg w-44 mt-12 ring-1 ring-soft-blue-100 dark:ring-gray-700 overflow-hidden">
                <ul className="py-2 text-sm text-soft-blue-700 dark:text-gray-300" aria-labelledby="dropdown-button">
                  {["All categories", "Name", "Country", "Region"].map((category) => (
                    <li key={category}>
                      <button 
                        type="button" 
                        onClick={() => handleCategorySelect(category)} 
                        className="w-full px-4 py-2 hover:bg-soft-blue-50 dark:hover:bg-gray-700 text-left transition-colors"
                      >
                        {category}
                      </button>
                    </li>
                  ))}
                </ul>
              </div>
            )}

            <div className="relative w-full">
              <input 
                type="search" 
                id="search-dropdown" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="block w-full p-2.5 text-sm text-soft-blue-900 dark:text-gray-200 bg-white dark:bg-gray-800 rounded-r-xl border-l-white dark:border-l-gray-800 border-l-2 border border-soft-blue-200 dark:border-gray-700 focus:ring-2 focus:ring-inset focus:ring-soft-blue-500 placeholder:text-soft-blue-400 dark:placeholder:text-gray-500 transition-all" 
                placeholder="Start typing..." 
              />
              <button 
                type="submit" 
                className="absolute top-0 right-0 p-2.5 text-sm font-medium h-full text-white bg-soft-blue-600 dark:bg-soft-blue-500 rounded-r-xl border border-soft-blue-600 dark:border-soft-blue-500 hover:bg-soft-blue-700 dark:hover:bg-soft-blue-600 focus:ring-2 focus:ring-inset focus:ring-soft-blue-500 transition-colors">
                <MagnifyingGlassIcon className="w-6 h-5" aria-hidden="true" />
                <span className="sr-only">Search</span>
              </button>
            </div>
          </div>
        </form>

        <div className="mt-12 max-w-xl mx-auto">
          {searchResults.length > 0 ? (
            searchResults.map((result) => (
              <SearchResult 
                key={result._id} 
                result={result}
                onAddToList={handleAddToList}
              />
            ))
          ) : (
            <p className="text-soft-blue-600 dark:text-gray-400 mt-8 text-sm">No results found. Start your search above.</p>
          )}
        </div>

        {searchResults.length > 0 && (
          <div className="mt-8 flex items-center justify-between max-w-xl mx-auto">
            <div className="flex items-center gap-2">
              <label htmlFor="itemsPerPage" className="text-sm text-soft-blue-600 dark:text-gray-400">
                Items per page:
              </label>
              <select
                id="itemsPerPage"
                value={itemsPerPage}
                onChange={(e) => {
                  setItemsPerPage(Number(e.target.value))
                  setCurrentPage(1)
                }}
                className="rounded-xl border-soft-blue-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm text-soft-blue-700 dark:text-gray-300 focus:ring-2 focus:ring-soft-blue-500"
              >
                {[5, 10, 20, 50].map((value) => (
                  <option key={value} value={value}>
                    {value}
                  </option>
                ))}
              </select>
            </div>

            <div className="flex items-center gap-2">
              <button
                onClick={() => handlePageChange(currentPage - 1)}
                disabled={currentPage === 1}
                className="px-4 py-2 text-sm rounded-full bg-white dark:bg-gray-800 text-soft-blue-700 dark:text-gray-300 border border-soft-blue-200 dark:border-gray-700 hover:bg-soft-blue-50 dark:hover:bg-gray-700 disabled:opacity-50 transition-colors"
              >
                Previous
              </button>
              <span className="text-sm text-soft-blue-600 dark:text-gray-400 py-1 px-2">
                Page {currentPage}
              </span>
              <button
                onClick={() => handlePageChange(currentPage + 1)}
                disabled={currentPage * itemsPerPage >= totalResults}
                className="px-4 py-2 text-sm rounded-full bg-white dark:bg-gray-800 text-soft-blue-700 dark:text-gray-300 border border-soft-blue-200 dark:border-gray-700 hover:bg-soft-blue-50 dark:hover:bg-gray-700 disabled:opacity-50 transition-colors"
              >
                Next
              </button>
            </div>
          </div>
        )}
      </div>

    </div>
  )
}
